import { streamText } from 'ai';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 2500); // Edge limit

  try {
    const result = await streamText({
      model: openai('gpt-4o-mini'),
      // ... config
      signal: controller.signal,
    });

    clearTimeout(timeout);
    // Stream to client
  } catch (error) {
    if (error.name === 'AbortError') {
      res.status(408).json({ error: 'timeout' });
    }
  }
}

async function voiceAgentPipeline(audio: Buffer) {
  // 1. Speech-to-Text
  const transcript = await deepgram.transcribe(audio);

  // 2. LLM Reasoning
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: transcript,
  });

  // 3. Collect full response
  let fullResponse = '';
  for await (const chunk of result.textStream) {
    fullResponse += chunk;
  }

  // 4. Text-to-Speech
  const audioResponse = await elevenlabs.generate({
    text: fullResponse,
    voice: 'default',
  });

  return audioResponse;
}

