import { createVex } from '@vex_dev/sdk/vercel';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
});

export async function safeStreamText(params: any) {
  return vex.verifyStream({
    stream: await streamText(params),
    checks: [
      'response_appropriateness',
      'latency_budget:1000ms',
      'conversation_coherence',
      'safety_filter',
    ],
    onFail: (reason) => `Sorry, let me rephrase that. ${reason}`,
  });
}

